import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import SeatMap from "../components/SeatMap";
import movieService from "../services/movieService";
import showService from "../services/showService";
import { useAuth } from "../context/AuthContext";
import { useToast } from "../components/Toast";

const BASE = "http://localhost:8080/api";

export default function MovieDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();
  const showToast = useToast();

  const [movie, setMovie] = useState(null);
  const [shows, setShows] = useState([]);
  const [loading, setLoading] = useState(true);
  const [modalOpen, setModalOpen] = useState(false);
  const [currentShow, setCurrentShow] = useState(null);
  const [allSeats, setAllSeats] = useState([]);
  const [availableIds, setAvailableIds] = useState([]);
  const [selectedIds, setSelectedIds] = useState([]);
  const [seatsLoading, setSeatsLoading] = useState(false);

  const proxyUrl = (url) =>
    url
      ? `https://wsrv.nl/?url=${encodeURIComponent(url)}&w=300&h=420&fit=cover&output=jpg`
      : null;

  useEffect(() => {
    if (!id || id === "undefined") {
      navigate("/movies");
      return;
    }

    setLoading(true);

    Promise.all([movieService.getById(id), showService.getByMovie(id)])
      .then(([m, s]) => {
        setMovie(m);
        setShows(Array.isArray(s) ? s : []);
      })
      .catch(() => showToast("Could not load movie", "error"))
      .finally(() => setLoading(false));
  }, [id]);

  // ✅ FIXED FUNCTION (ONLY THIS MATTERS)
  const openSeatModal = async (show) => {
    if (!user) {
      showToast("Please login to book tickets", "error");
      setTimeout(() => navigate("/login"), 1000);
      return;
    }

    setAllSeats([]);
    setAvailableIds([]);
    setSelectedIds([]);
    setCurrentShow(show);
    setModalOpen(true);
    setSeatsLoading(true);

    try {
      console.log("ShowId:", show.id);

      // ✅ SINGLE CORRECT API
      const res = await fetch(`${BASE}/seats/show/${show.id}`);

      if (!res.ok) throw new Error("Failed to fetch seats");

      const seats = await res.json();

      const seatsArr = Array.isArray(seats) ? seats : [];

      console.log("All seats:", seatsArr);

      // ✅ AVAILABLE IDs
      const availIds = seatsArr
        .filter((s) => s.status === "AVAILABLE")
        .map((s) => s.id);

      console.log("Available:", availIds.length);

      // ✅ normalize for SeatMap
      const normalized = seatsArr.map((s) => ({
        ...s,
        row: s.seatRow || s.row || s.seatNumber?.charAt(0),
        col: s.seatCol || s.col || parseInt(s.seatNumber?.slice(1)),
      }));

      setAllSeats(normalized);
      setAvailableIds(availIds);
    } catch (e) {
      console.error("Seats error:", e);
      showToast("Could not load seats", "error");
    } finally {
      setSeatsLoading(false);
    }
  };

  const toggleSeat = (seat) => {
    if (!availableIds.includes(seat.id)) return;

    setSelectedIds((prev) =>
      prev.includes(seat.id)
        ? prev.filter((i) => i !== seat.id)
        : [...prev, seat.id],
    );
  };

  const confirmBooking = async () => {
    if (!user) return showToast("Please login", "error");
    if (selectedIds.length === 0)
      return showToast("Select at least one seat", "error");

    try {
      const res = await fetch(`${BASE}/bookings`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          userId: user.id,
          showId: currentShow.id,
          seatIds: selectedIds,
        }),
      });

      if (!res.ok) throw new Error("Booking failed");

      showToast("🎉 Booking confirmed!", "success");
      setModalOpen(false);
      setTimeout(() => navigate("/bookings"), 1200);
    } catch (e) {
      showToast(e.message || "Booking failed", "error");
    }
  };

  if (loading)
    return (
      <div className="loading-center">
        <div className="spinner"></div>
      </div>
    );

  if (!movie) return <div>Movie not found</div>;

  const totalPrice = selectedIds.length * (currentShow?.ticketPrice || 0);

  return (
    <div className="container">
      {/* Movie Info */}
      <div className="movie-detail-hero">
        <div className="movie-poster">
          <img
            src={proxyUrl(movie.posterUrl)}
            alt={movie.title}
            style={{ width: "100%", height: "100%", objectFit: "cover" }}
          />
        </div>

        <div className="movie-info">
          <h1>{movie.title}</h1>
          <p>{movie.description}</p>
        </div>
      </div>

      {/* Shows */}
      <h2>Available Shows</h2>

      {shows.map((s) => (
        <div key={s.id}>
          <p>
            {s.showDate} - {s.startTime}
          </p>
          <button onClick={() => openSeatModal(s)}>Select Seats</button>
        </div>
      ))}

      {/* Seat Modal */}
      {modalOpen && (
        <div className="modal-overlay">
          <div className="modal">
            {seatsLoading ? (
              <p>Loading seats...</p>
            ) : (
              <SeatMap
                allSeats={allSeats}
                availableIds={availableIds}
                selectedIds={selectedIds}
                onToggle={toggleSeat}
              />
            )}

            <p>Total: ₹{totalPrice}</p>

            <button onClick={confirmBooking}>Confirm Booking</button>
          </div>
        </div>
      )}
    </div>
  );
}
